package genxsolution.vms.vmsbackend.maintenance_management.repair_job.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.repair_job.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.repair_job.service.RepairJobService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/repair-jobs") public class RepairJobController { private final RepairJobService service; public RepairJobController(RepairJobService service){this.service=service;} @GetMapping public List<RepairJobResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public RepairJobResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public RepairJobResponse create(@RequestBody RepairJobUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public RepairJobResponse update(@PathVariable UUID id,@RequestBody RepairJobUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
